async function actualizarMetricas() {
    if 
(!sucursalId) return;

    const hoy       = new Date();
    const hoyInicio = new Date(hoy); hoyInicio.setHours(0, 
0, 0, 0);
    const hoyFin    = new Date(hoy); hoyFin.setHours(23, 59, 59, 999);

    // Semana actual
    const 
diaSem    = hoy.getDay();
    const diffLunes = (diaSem === 0 ? -6 : 1 - diaSem);
    const lunes     = new 
Date(hoy); lunes.setDate(hoy.getDate() + diffLunes); lunes.setHours(0, 0, 0, 0);
    const viernes   = new 
Date(lunes); viernes.setDate(lunes.getDate() + 4); viernes.setHours(23, 59, 59, 999);

    try {
        const 
[resSemana, resToday, resCirugias] = await Promise.all([
            // Citas de la semana

conexionSupabase
                .from('citas')
                .select('id', { count: 'exact', head: true })

          .eq('sucursal_id', sucursalId)
                .gte('fecha_hora', lunes.toISOString())

.lte('fecha_hora', viernes.toISOString()),

            // Pacientes atendidos hoy (estatus finalizada/completada)

           conexionSupabase
                .from('citas')
                .select('id', { count: 'exact', head: 
true })
                .eq('sucursal_id', sucursalId)
                .in('estatus', ['finalizada', 
'completada'])
                .gte('fecha_hora', hoyInicio.toISOString())
                .lte('fecha_hora', 
hoyFin.toISOString()),

            // CirugÃas programadas esta semana
            conexionSupabase

  .from('citas')
                .select('id', { count: 'exact', head: true })
                .eq('sucursal_id', 
sucursalId)
                .ilike('motivo_breve', '%cirug%')
                .gte('fecha_hora', 
lunes.toISOString())
                .lte('fecha_hora', viernes.toISOString()),
        ]);

        const 
elAtendidos = document.getElementById('metrica-atendidos');
        const elSemana    = 
document.getElementById('metrica-citas-semana');
        const elCirugias  = 
document.getElementById('metrica-cirugias');

        if (elAtendidos) elAtendidos.textContent = resToday.count ?? 
0;
        if (elSemana)    elSemana.textContent    = resSemana.count ?? 0;
        if (elCirugias)  
elCirugias.textContent  = resCirugias.count ?? 0;

    } catch (err) {
        console.warn('[AGENDA] Error al 
actualizar mÃ©tricas:', err.message);
    }
}

